mapper.select:
SELECT ca.id, ca.club_id, ca.initiator_user_id, c.club_name, ca.apply_status, u.real_name AS initiator_real_name, ca.created_at FROM `club_apply` ca JOIN `club` c ON c.id = ca.club_id LEFT JOIN `user` u ON u.id = ca.initiator_user_id WHERE ca.is_deleted = 0 AND c.is_deleted = 0
AND ca.apply_status = #{applyStatus}
AND c.club_name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY ca.created_at DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(1) FROM `club_apply` ca JOIN `club` c ON c.id = ca.club_id WHERE ca.is_deleted = 0 AND c.is_deleted = 0
AND ca.apply_status = #{applyStatus}
AND c.club_name LIKE CONCAT('%', #{keyword}, '%')

SELECT cc.id, cc.club_id AS club_id, c.club_name AS club_name, u.real_name AS initiator_real_name, cc.apply_type AS apply_type, cc.apply_reason AS apply_reason, cc.asset_settlement_url AS asset_settlement_url, cc.cancel_status AS cancel_status, cc.created_at AS created_at FROM `club_cancel` cc JOIN `club` c ON c.id = cc.club_id LEFT JOIN `user` u ON u.id = cc.created_by WHERE cc.is_deleted = 0 AND c.is_deleted = 0
AND cc.cancel_status = #{cancelStatus}
AND c.club_name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY cc.created_at DESC, cc.id DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(1) FROM `club_cancel` cc JOIN `club` c ON c.id = cc.club_id WHERE cc.is_deleted = 0 AND c.is_deleted = 0
AND cc.cancel_status = #{cancelStatus}
AND c.club_name LIKE CONCAT('%', #{keyword}, '%')

