mapper.select:
SELECT c.id AS club_id, c.club_name AS club_name, c.category AS category, c.status AS status, ca.apply_status AS apply_status, u.real_name AS initiator_real_name, c.instructor_name AS instructor_name FROM `club` c LEFT JOIN `club_apply` ca ON ca.id = ( SELECT ca2.id FROM `club_apply` ca2 WHERE ca2.club_id = c.id AND ca2.is_deleted = 0 ORDER BY ca2.created_at DESC, ca2.id DESC LIMIT 1 ) LEFT JOIN `user` u ON u.id = ca.initiator_user_id WHERE c.is_deleted = 0
AND c.club_name LIKE CONCAT('%', #{keyword}, '%')
AND c.category = #{category}
ORDER BY c.updated_at DESC, c.id DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(1) FROM `club` c WHERE c.is_deleted = 0
AND c.club_name LIKE CONCAT('%', #{keyword}, '%')
AND c.category = #{category}

