UPDATE `event`
SET event_status = 6,
    updated_at = #{now}
WHERE event_status = 3
  AND start_at <= #{now}
  AND is_deleted = 0

UPDATE `event`
SET event_status = 4,
    updated_at = #{now}
WHERE event_status = 6
  AND end_at < #{now}
  AND is_deleted = 0

mapper.select:
SELECT (
    SELECT COUNT(1) FROM `club_apply` WHERE is_deleted = 0 AND apply_status IN (1, 2, 3)
) + (
    SELECT COUNT(1) FROM `club_cancel` WHERE is_deleted = 0 AND cancel_status IN (1, 2, 3)
) + (
    SELECT COUNT(1) FROM `event` WHERE is_deleted = 0 AND event_status = 2
)

