SELECT e.id, e.title, e.location, e.start_at AS start_at, e.end_at AS end_at, e.limit_count AS limit_count, IFNULL(s.cnt, 0) AS signup_count, IFNULL(ck.cnt, 0) AS checkin_count, e.event_status AS event_status, e.reject_reason AS reject_reason, CASE WHEN es.id IS NOT NULL THEN TRUE ELSE FALSE END AS has_summary, e.created_at AS created_at FROM `event` e LEFT JOIN (SELECT event_id, COUNT(1) AS cnt FROM `event_signup` WHERE signup_status = 1 AND is_deleted = 0 GROUP BY event_id) s ON s.event_id = e.id LEFT JOIN (SELECT event_id, COUNT(1) AS cnt FROM `event_checkin` WHERE is_deleted = 0 GROUP BY event_id) ck ON ck.event_id = e.id LEFT JOIN `event_summary` es ON es.event_id = e.id AND es.is_deleted = 0 WHERE e.club_id = #{clubId} AND e.is_deleted = 0
AND e.event_status = #{eventStatus}
ORDER BY e.created_at DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(1) FROM `event` e
WHERE e.club_id = #{clubId} AND e.is_deleted = 0

    AND e.event_status = #{eventStatus}

SELECT e.id, e.club_id AS club_id, c.club_name AS club_name, e.title, e.location, e.start_at AS start_at, e.end_at AS end_at, e.limit_count AS limit_count, e.event_status AS event_status, e.created_at AS created_at FROM `event` e JOIN `club` c ON c.id = e.club_id WHERE e.is_deleted = 0
AND e.event_status = #{eventStatus}
AND (e.title LIKE CONCAT('%', #{keyword}, '%') OR c.club_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY e.created_at DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(1) FROM `event` e JOIN `club` c ON c.id = e.club_id WHERE e.is_deleted = 0
AND e.event_status = #{eventStatus}
AND (e.title LIKE CONCAT('%', #{keyword}, '%') OR c.club_name LIKE CONCAT('%', #{keyword}, '%'))

