SELECT es.id, es.event_id AS eventId, e.title AS eventTitle, c.club_name AS clubName, es.summary_text AS summaryText, es.summary_images AS summaryImagesJson, es.feedback_score AS feedbackScore, es.issue_reflection AS issueReflection, es.attachment_url AS attachmentUrl, es.created_at AS createdAt FROM `event_summary` es JOIN `event` e ON e.id = es.event_id AND e.is_deleted = 0 JOIN `club` c ON c.id = e.club_id WHERE es.is_deleted = 0
AND (e.title LIKE CONCAT('%', #{keyword}, '%') OR c.club_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY es.created_at DESC LIMIT #{pageSize} OFFSET #{offset}

