mapper.select:
SELECT e.id, e.club_id, c.club_name, e.event_id, e.category, e.amount, e.payee_name, e.payee_account, e.invoice_url, e.expense_desc, e.approve_level, e.expense_status, e.reject_reason, e.created_at, e.updated_at FROM `expense` e JOIN `club` c ON c.id = e.club_id WHERE e.club_id = #{clubId} AND e.is_deleted = 0
AND e.expense_status = #{expenseStatus}
ORDER BY e.created_at DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(1) FROM `expense` e
WHERE e.club_id = #{clubId} AND e.is_deleted = 0

    AND e.expense_status = #{expenseStatus}

SELECT e.id, e.club_id, c.club_name, e.amount, e.category, e.expense_desc, e.expense_status, e.invoice_url, e.created_at FROM `expense` e JOIN `club` c ON c.id = e.club_id WHERE e.approve_level = 2 AND e.expense_status = 1 AND e.is_deleted = 0 AND c.is_deleted = 0
AND (c.club_name LIKE CONCAT('%', #{keyword}, '%') OR e.expense_desc LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY e.created_at ASC LIMIT #{pageSize} OFFSET #{offset}

SELECT l.id, l.club_id, l.biz_type,
       CASE WHEN l.biz_type = 1 THEN '收入' ELSE '支出' END AS biz_type_name,
       l.biz_id, l.change_amount, l.balance_after, l.occur_at
FROM `ledger` l
WHERE l.club_id = #{clubId} AND l.is_deleted = 0

    AND l.biz_type = #{bizType}


    AND l.occur_at >= #{startTime}


    AND l.occur_at <= #{endTime}

ORDER BY l.occur_at DESC, l.id DESC
LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(1) FROM `ledger` l
WHERE l.club_id = #{clubId} AND l.is_deleted = 0

    AND l.biz_type = #{bizType}


    AND l.occur_at >= #{startTime}


    AND l.occur_at <= #{endTime}

SELECT COUNT(1) FROM `expense`
WHERE club_id = #{clubId} AND is_deleted = 0 AND YEAR(created_at) = #{year}
  AND ((amount > 500 AND approve_level = 1) OR invoice_url IS NULL OR invoice_url = '')

SELECT e.id, e.club_id, c.club_name, e.amount, e.category, e.expense_desc, e.approve_level, e.expense_status, e.invoice_url, e.reject_reason, e.created_at, CASE WHEN (e.amount > 500 AND e.approve_level = 1) AND (e.invoice_url IS NULL OR e.invoice_url = '') THEN '金额超500未经学校审批且缺少发票' WHEN e.amount > 500 AND e.approve_level = 1 THEN '金额超500未经学校审批' WHEN e.invoice_url IS NULL OR e.invoice_url = '' THEN '缺少发票凭证' ELSE '未知异常' END AS anomaly_reason FROM `expense` e JOIN `club` c ON c.id = e.club_id AND c.is_deleted = 0 WHERE e.is_deleted = 0 AND ((e.amount > 500 AND e.approve_level = 1) OR e.invoice_url IS NULL OR e.invoice_url = '')
AND (c.club_name LIKE CONCAT('%', #{keyword}, '%') OR e.expense_desc LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY e.created_at DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT cr.id, cr.club_id, c.club_name, cr.review_year, cr.review_status, cr.score, cr.reject_reason, cr.created_at, cr.updated_at FROM `club_review` cr JOIN `club` c ON c.id = cr.club_id WHERE cr.is_deleted = 0
AND cr.review_status = #{reviewStatus}
AND c.club_name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY cr.updated_at DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(1) FROM `club_review` cr JOIN `club` c ON c.id = cr.club_id WHERE cr.is_deleted = 0
AND cr.review_status = #{reviewStatus}
AND c.club_name LIKE CONCAT('%', #{keyword}, '%')

